// Vérification basique + extraction données Stripe
const payload = $input.first().json.body || $input.first().json;

// Ignorer les événements non pertinents
if (payload.type !== 'payment_intent.succeeded') {
  throw new Error(`Événement ignoré : ${payload.type}`);
}

const pi = payload.data?.object || {};
const metadata = pi.metadata || {};

// Extraire les données commande depuis les metadata Stripe
const commande = {
  id: pi.id,
  reference: metadata.order_id || pi.id.slice(-8).toUpperCase(),
  montant: (pi.amount / 100).toFixed(2),
  currency: pi.currency?.toUpperCase() || 'EUR',
  statut: 'confirmée',
  dateISO: new Date(pi.created * 1000).toISOString(),
  dateFr: new Date(pi.created * 1000).toLocaleString('fr-FR', { timeZone: 'Indian/Reunion' }),
  articles: metadata.articles ? JSON.parse(metadata.articles) : [],
  livraisonType: metadata.livraison_type || 'livraison',
  adresseLivraison: metadata.adresse_livraison || 'À récupérer sur place'
};

const client = {
  nom: pi.shipping?.name || metadata.client_nom || 'Client',
  email: metadata.client_email || pi.receipt_email || '',
  telephone: pi.shipping?.phone || metadata.client_telephone || ''
};

const config = {
  nomEtablissement: metadata.etablissement || 'La Boutique',
  emailGerant: metadata.email_gerant || '',
  emailExpedition: metadata.email_expedition || 'commandes@marrynov.re'
};

return [{ json: { commande, client, config } }];
